#!/usr/bin/env node
/**
 * Toast Match Preview — dry run of the proposed name-matching logic
 *
 * Loads the most recent Toast menu dump (`tools/toast-menu-dump.json`,
 * generated by `tools/toast-probe.js`) and the local oyster catalog
 * (`data/oysters.js`), then runs the proposed normalized-name matching against
 * the Raw Bar group. Prints categorized results so we can decide what the
 * production sync should auto-accept vs. surface for admin-UI mapping.
 *
 * No production code is touched and no network calls are made — this is a
 * local-only diagnostic against existing files.
 *
 * Usage (from Oyster Website folder):
 *   node tools/toast-match-preview.js
 *
 * Requirements: Node 18+. Run `node tools/toast-probe.js` first if the dump
 * file is missing or stale.
 */

const fs = require('fs');
const path = require('path');
const vm = require('vm');

// ---- 1. Load Toast menu dump ----------------------------------------------
const dumpPath = path.join(__dirname, 'toast-menu-dump.json');
if (!fs.existsSync(dumpPath)) {
  console.error(`ERROR: ${dumpPath} not found. Run \`node tools/toast-probe.js\` first.`);
  process.exit(1);
}
const dump = JSON.parse(fs.readFileSync(dumpPath, 'utf8'));

// ---- 2. Load local catalog -------------------------------------------------
// data/oysters.js is a browser file — `var OYSTERS = [...]`. Evaluate it in a
// fresh VM context to extract the array without polluting our module.
const catalogPath = path.join(__dirname, '..', 'data', 'oysters.js');
const catalogCode = fs.readFileSync(catalogPath, 'utf8');
const sandbox = {};
vm.createContext(sandbox);
vm.runInContext(catalogCode, sandbox);
const OYSTERS = sandbox.OYSTERS;
if (!Array.isArray(OYSTERS) || !OYSTERS.length) {
  console.error(`ERROR: data/oysters.js did not produce an OYSTERS array.`);
  process.exit(1);
}

// ---- 3. Normalization + matching helpers ----------------------------------
function normalize(s) {
  return String(s || '').toLowerCase().replace(/[^a-z0-9]/g, '');
}

// Build catalog lookup indexes: normalized id → entry, normalized name → entry.
const byNormId = new Map();
const byNormName = new Map();
for (const o of OYSTERS) {
  byNormId.set(normalize(o.id), o);
  byNormName.set(normalize(o.name), o);
}

// Iterative Levenshtein, single-row.
function levenshtein(a, b) {
  if (a === b) return 0;
  const la = a.length;
  const lb = b.length;
  if (!la) return lb;
  if (!lb) return la;
  let prev = new Array(lb + 1);
  let curr = new Array(lb + 1);
  for (let j = 0; j <= lb; j++) prev[j] = j;
  for (let i = 1; i <= la; i++) {
    curr[0] = i;
    for (let j = 1; j <= lb; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      curr[j] = Math.min(curr[j - 1] + 1, prev[j] + 1, prev[j - 1] + cost);
    }
    [prev, curr] = [curr, prev];
  }
  return prev[lb];
}

/**
 * Try to match a Toast item name against a catalog entry, working through
 * progressively fuzzier strategies. Returns the strategy that hit, the matched
 * catalog entry (or null), and Levenshtein distance for `near` matches.
 */
function findMatch(toastName) {
  const norm = normalize(toastName);
  if (!norm) return { strategy: 'empty', oyster: null };

  // Tier 1: exact normalized match against catalog name or id.
  if (byNormName.has(norm)) return { strategy: 'exact', oyster: byNormName.get(norm) };
  if (byNormId.has(norm)) return { strategy: 'exact-id', oyster: byNormId.get(norm) };

  // Tier 2: handle trailing-s plural mismatch in either direction.
  if (norm.endsWith('s')) {
    const stripped = norm.slice(0, -1);
    if (byNormName.has(stripped)) return { strategy: 'plural', oyster: byNormName.get(stripped) };
    if (byNormId.has(stripped)) return { strategy: 'plural', oyster: byNormId.get(stripped) };
  }
  if (byNormName.has(norm + 's')) return { strategy: 'plural-rev', oyster: byNormName.get(norm + 's') };
  if (byNormId.has(norm + 's')) return { strategy: 'plural-rev', oyster: byNormId.get(norm + 's') };

  // Tier 3: Levenshtein within distance 2 across both indexes.
  let best = null;
  const tryNear = (k, v) => {
    if (Math.abs(k.length - norm.length) > 2) return; // quick reject
    const d = levenshtein(norm, k);
    if (d <= 2 && (!best || d < best.distance)) best = { strategy: 'near', oyster: v, distance: d };
  };
  for (const [k, v] of byNormName) tryNear(k, v);
  for (const [k, v] of byNormId) tryNear(k, v);
  if (best) return best;

  // Tier 4: substring containment, with a length floor to avoid silly hits.
  if (norm.length >= 5) {
    for (const [k, v] of byNormName) {
      if (k.length >= 5 && (k.includes(norm) || norm.includes(k))) {
        return { strategy: 'substring', oyster: v };
      }
    }
    for (const [k, v] of byNormId) {
      if (k.length >= 5 && (k.includes(norm) || norm.includes(k))) {
        return { strategy: 'substring-id', oyster: v };
      }
    }
  }

  return { strategy: 'none', oyster: null };
}

// ---- 4. Walk Raw Bar items -------------------------------------------------
const menus = Array.isArray(dump) ? dump : (dump.menus || []);
const buckets = {
  exact: [],
  'exact-id': [],
  plural: [],
  'plural-rev': [],
  near: [],
  substring: [],
  'substring-id': [],
  none: [],
};
let totalSeen = 0;

for (const menu of menus) {
  for (const group of (menu.menuGroups || [])) {
    if (group.name !== 'Raw Bar') continue;
    for (const item of (group.menuItems || [])) {
      totalSeen++;
      const m = findMatch(item.name);
      buckets[m.strategy].push({
        toastName: item.name,
        toastGuid: item.guid,
        oyster: m.oyster,
        distance: m.distance,
      });
    }
  }
}

// ---- 5. Catalog entries that didn't match anything in Toast ---------------
const matchedCatalogIds = new Set();
for (const key of ['exact', 'exact-id', 'plural', 'plural-rev', 'near', 'substring', 'substring-id']) {
  for (const e of buckets[key]) if (e.oyster) matchedCatalogIds.add(e.oyster.id);
}
const catalogOnly = OYSTERS.filter((o) => !matchedCatalogIds.has(o.id));

// ---- 6. Render ------------------------------------------------------------
const totalConfident = buckets.exact.length + buckets['exact-id'].length;
const totalLightlyFuzzy = buckets.plural.length + buckets['plural-rev'].length;
const totalSpeculative = buckets.near.length + buckets.substring.length + buckets['substring-id'].length;
const totalUnmatched = buckets.none.length;

console.log(`\n=== Toast Raw Bar match preview ===`);
console.log(`Total Raw Bar items:         ${totalSeen}`);
console.log(`Confident (exact / id):      ${totalConfident}`);
console.log(`Lightly fuzzy (plural):      ${totalLightlyFuzzy}`);
console.log(`Speculative (near/substr):   ${totalSpeculative}`);
console.log(`Unmatched (admin UI / non-oyster): ${totalUnmatched}`);

function printBucket(label, entries) {
  if (!entries.length) return;
  console.log(`\n--- ${label} (${entries.length}) ---`);
  for (const e of entries) {
    if (e.oyster) {
      const dist = e.distance != null ? `  [Levenshtein ${e.distance}]` : '';
      console.log(`  "${e.toastName}"  →  ${e.oyster.id}  (${e.oyster.name})${dist}`);
    } else {
      console.log(`  "${e.toastName}"`);
    }
  }
}

printBucket('EXACT name match', buckets.exact);
printBucket('EXACT id match', buckets['exact-id']);
printBucket('PLURAL — Toast plural / catalog singular', buckets.plural);
printBucket('PLURAL-REV — Toast singular / catalog plural', buckets['plural-rev']);
printBucket('NEAR — Levenshtein ≤ 2', buckets.near);
printBucket('SUBSTRING (name index)', buckets.substring);
printBucket('SUBSTRING (id index)', buckets['substring-id']);
printBucket('UNMATCHED — needs admin-UI mapping or is a non-oyster Raw Bar item', buckets.none);

console.log(`\n--- Catalog oysters with NO match in Toast Raw Bar (${catalogOnly.length}) ---`);
console.log(`(These are oysters in data/oysters.js that aren't on the current Toast menu — staff would need to add them to Toast for them to appear on the website.)`);
for (const o of catalogOnly) {
  console.log(`  ${o.id}  (${o.name})`);
}

console.log(`\nDecide based on this output: which strategies are safe to auto-apply, and which should route to the admin UI for human confirmation. Speculative tier (NEAR/SUBSTRING) is the policy boundary worth scrutinizing.`);
